sp_widget.client_script:
function widgetClientController($scope, $location, spUtil, $rootScope, amb, $http, spAriaUtil, $timeout, spModal, dtechOrganizationalUser) {
    // Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
    // Script Continued Below
    //------------------------------------------------------------------------------------------------------------------------
    var c = this;
    c.refresh = function() {
        //KT: STRY0065140
        if (c.data.page_id != "discovertasker_processtemplatedetails") {
            spUtil.update($scope).then(function() {
                c.data = $scope.data;
            });
        }
    };

		// STRY0135710
    $scope.tableFilterButtonSelected = function(filterSelected){
      c.data.tableFilterButtonSelected=filterSelected;
      $scope.loadingData = true;
      $scope.server.update().then(function() {
        $scope.loadingData = false;
        loadFilterWidget();
        $scope.$emit("discovertasker-widget-data-table-update_count", {
          count: c.data.row_count,
          title: c.data.title || c.data.table_plural
        });

      });

    }

    // STRY0120403
    $scope.changeFilter = function(filterToUse) {
        $scope.data.taskFilter = filterToUse;
        c.data.taskFilter = filterToUse;
        spUtil.update($scope);
    };
    /*
    $("td:contains(true)").css("color","green");
    $("td:contains(false)").css("color","red");
    */

    /*
     * options:
     * hide_footer (bool) = true to remove the data table footer contents
     * hide_header (bool) = true to remove the data table header contents
     * show_new (bool) = true to show the "New" record button
     * show_keywords (bool) = true to show the keyword search field
     * table (string) = the table name to query
     * filter (string) = the encoded query
     * o (string) = the order by column
     * d (string) = The order by direction: asc or desc
     * p (int) = the page to jump to
     * fields (string) = comma seperated list of fields that become the list columns
     * view (string) = the default view to load for columns, overrides fields
     */

    if (c.data.fromModal === true)
        c.refresh();

    // Sets the diffrent exporting data types that this table is capable of producing
    $scope.exportTypes = [{
        label: 'PDF',
        value: 'PDF'
    }, {
        label: 'Excel',
        value: 'EXCEL'
    }, {
        label: 'CSV',
        value: 'CSV'
    }];
    var keys = ['table', 'filter', 'p', 'o', 'd'];

    // Sets an eventNames data object to be used in diffrent functions based on events
    var eventNames = {
        click: 'data_table.click',
        setFilter: 'data_table.setFilter',
        setKeywords: 'data_table.setKeywords'
    };

    // Listens to a declareActiveTab event to define the active tab in the data table
    $rootScope.$on('declareActiveTab', function(event, activeTab) {
        c.activeTab = activeTab;
    });

		// STRY0135276 - POC - Data Table - Response Comment Update - User Profile Directive
		$scope.getTitle = function(item){
			var title = "";
			var taskerNumber = item.taskernumber;
			var shortDescription = item.short_description;
			if(taskerNumber){
				title = taskerNumber.value;
			}
			if(shortDescription){
				if(taskerNumber){
					title += " - "
				}
				title += shortDescription.value;
			}
			return title;
		}

		// STRY0135276 - by moving the condition into Client script, the HTML is much cleaner
		$scope.openRecord = function(item){
			if(c.data.open_row_details_in_modal == true){
				$scope.openModal(item);
			} else {
				$scope.goTasker(c.data.table, item);
			}
		}

    $scope.goTasker = function(table, item) {
        var parms = {};
        parms.table = table;
        parms.sys_id = item.sys_id;
        parms.record = item;
        $scope.ignoreLocationChange = true;
        for (var x in c.data.list) {
            c.data.list[x].selected = false;
        }
        item.selected = true;

        $rootScope.$emit('dataTableClick', item);
        var currentPageId = $location.search()['id'];
        //KT: STRY0065140
        if ((currentPageId != ("discovertasker_processtemplatelist")) && (currentPageId != "discovertasker_processtemplatedetails")) {
            // STRY0101803 added this to use Tasker Data Table for styling on the drill down page
            // STRY0117939
						// STRY0135701 - broadcast click on the list bifold view -NOTE: might be better to make this a setting
            if (currentPageId == "discovertasker_detailsdrilldown" ||
                currentPageId == "organizational_hierarchy_table" ||
								currentPageId == "task_list_bifold") {
                var p = $scope.data.page_id || 'form';
                var s = {
                    id: p,
                    table: parms.table,
                    sys_id: parms.sys_id,
                    view: $scope.data.view
                };
                $rootScope.$broadcast('$sp.list.click', s);
            } else {
                $scope.$emit(eventNames.click, parms);
            }
        }

    };
    //------------------------------------------------------------------------------------------------------------------------
    // CUSTOM: MODAL
    //------------------------------------------------------------------------------------------------------------------------
    $scope.openModal = function(item) {

        for (var x in c.data.items) {
            c.data.items[x].selected = false;
        }

        item.selected = true;
        $scope.data.selected = item;

        /* opens the platform form in a modal for this table */
        spModal.open({
            title: $scope.data.table_label,
            backdrop: 'static',
            widget: 'discovertasker-formtab',
            //STRY0065050: Get view from scope
            widgetInput: {
                table: $scope.data.table,
                sys_id: item.sys_id,
                view: $scope.data.view,
                isModal: true
            },
            size: 'lg',
            buttons: [],
            // 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
            footerStyle: {
                'display': 'none'
            }

        }).then(function() {
            /* update model after return from modal */
            c.server.update();
        });
        $("td").removeClass("selected");
    };

    // 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
    // function is not called, comment out block
    //     $scope.openModalProcessTemplate = function(item) {

    //         for (var x in c.data.items) {
    //             c.data.items[x].selected = false;
    //         }
    //         item.selected = true;
    //         $scope.data.selected = item;
    //         /* opens the platform form in a modal for this table */
    //         spModal.open({
    //             title: "Template Information",
    //             backdrop: 'static',
    //             widget: 'discovertasker-formtab',
    //             widgetInput: {
    //                 table: $scope.data.table,
    //                 sys_id: item.sys_id,
    //                 isModal: true
    //             },
    //             size: 'lg',
    //             buttons: []

    //         }).then(function() {
    //             /* update model after return from modal */
    //             c.server.update();
    //         });
    //     };
    function confirmAndSave() {
			var continueParent = true;
			if(c.widget.parent_form){
				continueParent = _checkFormChanges(c.widget.parent_form);
			}
			return continueParent;
		}

		function _checkFormChanges(check_g_form) {			
        // If the form is dirty, ask the user if they would like to save the record
        var continueOpen = false;
        var fMsg = '';
        var serializeChanges = check_g_form.serialize(true);
        if (serializeChanges.length > 0) {
            var changeFieldList = [];
            for (var field in serializeChanges) {
                changeFieldList.push(serializeChanges[field].label.trim());
            }
            fMsg = changeFieldList.join(', ');

            spModal.confirm("${Tasker - Modal Save Changes Message}  " + fMsg).then(function(confirmed) {
                check_g_form.save();
								// after confirmation and save, continue to open
								_continueToOpen();
            });
        } else {
            continueOpen = true;
        }
        return continueOpen;
    }

    function open_New_Modal(table, title, view, query) {
        var formQuery = query;
        // DFCT0010949 - open new widget for task table
        if (table == 'x_153465_discovert_route_task_instance') {
            spModal.open({
                title: title,
                message: '',
                backdrop: 'static',
                widget: 'new_tasker_selection',
                widgetInput: {
                    omit_icons: true,
                    table: table,
                    query: query,
                    sys_id: -1,
										// DFCT0011271
										u_servicenow_form_view: c.data.u_servicenow_form_view,
                    view: view, // NOTE, we may need to look up default
                    hideRelatedLists: true,
                    omitHeader: 'true',
                    hideAttachmentBtn: true,
                    isModal: true
                },
                shared: {},
                size: 'lg',
                buttons: [],
                footerStyle: {
                    'display': 'none'
                }
            });
        } else {
            spModal.open({
                title: title,
                backdrop: 'static',
                widget: 'discovertasker-formtab',
                widgetInput: {
                    table: table,
                    sys_id: "-1",
                    view: view,
                    query: formQuery,
                    // DFCT0010635
                    omitHeader: 'true',
                    // STRY0040294 - added isModal - added closing of open modal
                    isModal: true //,
                },
                size: 'lg',
                buttons: [],
                // 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
                footerStyle: {
                    'display': 'none'
                }
            });
        }
    }

		// This needed to be a separate function so it could be called after the change prompt modal
		// and also called if no prompt was necessary
		function _continueToOpen(){
			// DFCT0011298 - new email no longer a special case
			if (c.data.open_new_in_modal) {
						var title = 'New ' + c.data.table_label;
						if(c.data.newModalTitle){
							title = c.data.newModalTitle;
						}
						var view = $scope.data.view;
						if(c.data.newModalView){
							view = c.data.newModalView;
						}
						var filter = $scope.data.filter;
						if(c.data.newModalQuery){
							view = c.data.newModalQuery;
						}
            open_New_Modal(c.data.table, title, view, filter);
            return;
        } else {
					var parms = {
						id: 'form',
						table: $scope.data.table,
						view: $scope.data.view,
						sys_id: '-1'
					};
					if ($scope.data.filter != '')
						parms.query = $scope.data.filter;

					$location.search(parms);
				}

    }
    $scope.newRecord = function() {
        // check for save or cancel, call continue to open
        if (confirmAndSave())
            _continueToOpen();
		}

		// DFCT0011298 - no longer a special case, removed logic

		// STRY0109208 - Add Create Icon
		$scope.openCreateModal = function() {
						var title = 'New ' + c.data.table_label;
						if(c.data.newModalTitle){
							title = c.data.newModalTitle;
						}
						var view = $scope.data.view;
						if(c.data.newModalView){
							view = c.data.newModalView;
						}
						var filter = $scope.data.filter;
						if(c.data.newModalQuery){
							view = c.data.newModalQuery;
						}
			// DFCT0011271
			x_153465_discovert.twJS.openCreateModal(spModal, title, c.data.table, view, filter, c.data.u_servicenow_form_view);
		};	
    //------------------------------------------------------------------------------------------------------------------------
    // END CUSTOM
    //------------------------------------------------------------------------------------------------------------------------

    $scope.go = function(table, item) {
        var parms = {};
        parms.table = table;
        parms.sys_id = item.sys_id;
        parms.record = item;
        $scope.ignoreLocationChange = true;
        for (var x in c.data.list) {
            c.data.list[x].selected = false;
        }
        item.selected = true;
        $scope.$emit(eventNames.click, parms);
    };

    function recoverStateFromUrl() {
        $scope.data.fields = [];
        var s = $location.search();

        for (var x in keys) {
            if (s[keys[x]]) {
                $scope.data[keys[x]] = s[keys[x]];
            }
        }
        $scope.server.update().then(function(data) {
            if (s.sys_id) {
                for (var x in data.list) {
                    if (data.list[x].sys_id == s.sys_id) {
                        $scope.go(s.table, data.list[x]);
                    }
                }
            }
        });
    }

    if ($scope.options.fromUrl) {
        var origSearch = $location.search();
        $scope.$on('$locationChangeSuccess', function(e) {
            var s = $location.search();
            if (origSearch.id !== s.id)
                return;

            if ($scope.ignoreLocationChange) {
                $scope.ignoreLocationChange = false;
                return;
            }

            // Helps to recover state when using the browser's back button
            recoverStateFromUrl();
        });
    }


    $scope.getNumber = function(num) {
        return new Array(num);
    };

    $scope.mathMin = function(v1, v2) {
        return Math.min(v1, v2);
    };

    function getData(updateUrl) {
        var f = $scope.data;
        $scope.data.title = c.data.title;
        spUtil.update($scope).then(function(data) {
            f.view = data.view;
            if ($scope.options.fromUrl && updateUrl)
                setPermalink(f.table, f.filter, f.o, f.d, f.p);

            if ($scope.options.show_breadcrumbs && data.filterBreadcrumbs)
                $scope.$broadcast('widget-filter-breadcrumbs.setBreadcrumbs', data.filterBreadcrumbs.data, data.filter);

            initRecordWatcher(f.table, f.filter);
        });
    }

    function setPermalink(table, filter, orderBy, orderDirection, page) {
        $scope.ignoreLocationChange = true;
        var search = $location.search();
        angular.extend(search, {
            spa: 1,
            table: table,
            filter: filter,
            p: page,
            o: orderBy,
            d: orderDirection
        });
        $location.search(search);
    }

    var watcher;

    function initRecordWatcher(table, filter) {
        if (watcher)
            watcher.unsubscribe();

        if (table && filter) {
            // STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
            var params = {};
            var watcherChannel = amb.getChannelRW(table, filter);
            amb.connect();
            watcher = watcherChannel.subscribe(function(message) {
                if (!message.data)
                    return;
                switch (message.data.action) {
                    case "change":
                        updateRowFromRW(message);
                        break;
                    case "exit":
                        // A record was removed
                        // STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
                        // pass the table back to the form widget for the related list
                        params.table = c.data.table;
                        // pass the filter back to the form widget for the related list in case there are 2 related lists of the same table
                        params.filter = c.data.filter;
                        // 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating; emit sends rowCount in params, no need for .Deleted or .Added
                        // $rootScope.$broadcast('sp.DiscoverListItem.Deleted', params);
                        // spUtil.update($scope);
                        spUtil.update($scope).then(function() {
                            params.rowCount = $scope.data.row_count || 0;
                            $scope.$emit('sp.DiscoverListItem', params);
                        });
                        break;
                    case "entry":
                        // A record was added
                        // STRY0093948 - when a row is added, broadcast event to Tab Form with Tabs to update the count
                        // pass the table back to the form widget for the related list
                        params.table = c.data.table;
                        // pass the filter back to the form widget for the related list in case there are 2 related lists of the same table
                        params.filter = c.data.filter;
                        // 2.7.0 | 2021-05-21 | mmcc | STRY0099596 Record Watcher on Template Count not Updating; emit sends rowCount in params, no need for .Deleted or .Added
                        // $rootScope.$broadcast('sp.DiscoverListItem.Added', params);
                        //spUtil.update($scope);
                        spUtil.update($scope).then(function() {
                            params.rowCount = $scope.data.row_count || 0;
                            $scope.$emit('sp.DiscoverListItem', params);
                        });
                        break;
                    default:
                        spUtil.update($scope);
                        break;
                }
            });
        }
    }

    function updateRowFromRW(message) {
        if (message.data && message.data.sys_id && $scope.data.list) {
            var row, field;
            for (var i = 0; i < $scope.data.list.length; i++) {

                row = $scope.data.list[i];
                if (row.sys_id == message.data.sys_id) {
                    var fields = Object.getOwnPropertyNames(message.data.record);
                    for (var f in fields) {
                        field = fields[f];
                        if (typeof row[field] !== 'undefined') {
                            row[field].display_value = message.data.record[field].display_value;
                        }
                    }
                }
            }
        }
    }

    $scope.$on('$destroy', function() {
        if (watcher)
            watcher.unsubscribe();
    });

    $scope.setPageNum = function(num) {
        $scope.data.p = num;
        getData(true);
        $timeout(function() {
            $scope.focusOnTableHeader();
            // STRY0125255
            $scope.$emit("discovertasker-widget-data-table-update_page_index", {
                title: c.data.table_plural || c.data.title,
                page_index: $scope.data.p
            });

        });
    };

    $scope.setOrderBy = function(field) {
        var d = "asc";
        if ($scope.data.o == field) {
            if ($scope.data.d == "asc")
                d = "desc";
            else
                d = "asc";
        }

        if (d === "asc") {
            spAriaUtil.sendLiveMessage($scope.data.msg.sortingByAsc);
        } else if (d === "desc") {
            spAriaUtil.sendLiveMessage($scope.data.msg.sortingByDesc);
        }

        $scope.data.o = field;
        $scope.data.d = d;
        $scope.setSearch(true);
    };

    $scope.setSearch = function(updateUrl) {
        $scope.data.p = 1;
        getData(updateUrl);
    };

    $scope.$on(eventNames.setFilter, function(e, newFilter) {
        $scope.data.filter = newFilter;
        $scope.setSearch(false);
    });

    $scope.$on(eventNames.setKeywords, function(e, keywords) {
        $scope.data.keywords = keywords;
        $scope.setSearch(false);
    });

    $scope.$on('widget-filter-breadcrumbs.queryModified', function(e, newFilter) {
        $scope.data.filter = newFilter;
        // DFCT0010709
        $scope.data.breadcrumb_change = true;
        $scope.setSearch(true);
    });

    $scope.rowsWerePruned = function() {
        if (!$scope.data.list)
            return;

        $scope.rowsPruned = $scope.mathMin($scope.data.window_end, $scope.data.row_count) - $scope.data.window_start - $scope.data.list.length;
        return $scope.rowsPruned > 0;
    };

    $scope.showFilter = function() {
        return !$scope.data.list.length && !$scope.data.num_pages && !$scope.data.invalid_table && !$scope.loadingData;
    };

    c.appendQuery = function(query) {
        if ($scope.data.filter.length > 1)
            $scope.data.filter += '^';
        $scope.data.filter += query;
        $scope.setSearch();

    };
    // DFCT0010439 - "My Office" button on Organizational Hierarchy is displaying the wrong table/information
    if ($scope.data.table == undefined) {
        $scope.data = $scope.options;
    }
    // Makes Widget Async
    var title = $scope.data.title;
    if ($scope.options.use_instance_title == 'true')
        title = $scope.options.title;

    //jslog($scope.data.filter)
    $scope.loadingData = true;
    // STRY0120403 if filter changed, then record count will change and we will need to update the count
    var loadRowCount = c.data.row_count;
    $scope.server.update().then(function() {

        //if ($scope.data.newButtonUnsupported)
        //jslog("Service Portal: New button not supported for sys_attachment list");
        $scope.loadingData = false;
				// RAJ - follow up on this later
        $scope.data.title = title;
        initRecordWatcher($scope.data.table, $scope.data.filter);
        // STRY0120403 if filter changed, then record count will change and we will need to update the count
        if (loadRowCount != c.data.row_count) {
            $scope.$emit("discovertasker-widget-data-table-update_count", {
                count: c.data.row_count,
                title: c.data.title || c.data.table_plural
            });
        }
    });

    function parseQuery(table, queryString) {
        return $http.post('/api/now/sp/parsequery/' + table, queryString).then(function(response) {
            return response.data.result;
        });
    }

    c.createQueryTerm = function(table, field, sys_id, operator) {
        return $http.get('/api/now/sp/getInOutQueryTerm', {
            params: {
                table: table,
                sys_id: sys_id,
                field: field,
                operator: operator
            }
        }).then(function(response) {
            if (response && response.data && response.data.result)
                return response.data.result.parts;
        });
    };

    c.showMatching = function(field, newTerm) {
        var queryString = $scope.data.filter;
        var eq = "";
        parseQuery($scope.data.table, queryString).then(function(oldTerms) {
            for (var i = 0; i < oldTerms.length; i++) {
                var term = oldTerms[i];
                if (isSameField(newTerm, term))
                    continue;

                if (eq.length)
                    eq += '^';

                eq += getEncodedTerm(term);
            }
            if (eq.length)
                eq += '^';
            eq += getEncodedTerm(newTerm);

            $scope.data.filter = eq;
            $scope.setSearch();
        });
    };

    c.filterOut = function(field, newTerm) {
        var eq = $scope.data.filter;
        if (eq.length)
            eq += '^';

        eq += getEncodedTerm(newTerm);
        $scope.data.filter = eq;
        $scope.setSearch();
    };

    function isSameField(t1, t2) {
        if ('left' in t1 && 'left' in t2)
            return t1.left.field === t2.left.field;
        else if ('left' in t1)
            return t1.left.field === t2.field;
        else if ('left' in t2)
            return t1.field === t2.left.field;
        return t1.field === t2.field;
    }

    function getEncodedTerm(term) {
        var eq;
        if (term.left) {
            eq = getEncodedTerm(term.left);
            eq += '^OR';
            eq += getEncodedTerm(term.right);
        } else {
            eq = term.field;
            eq += term.operator;
            eq += term.value;
        }
        return eq;

    }


}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.02.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------

//------------------------------------------------------------------------------------------------------------------------
// 2.5.3 | 10.09.2020 | KT | UI  | STRY0083485: Console log error: Status field
//------------------------------------------------------------------------------------------------------------------------

/* 2.8.1 | 2022-11-25 | raj  | STRY0131544 Org Hierarchy Member Lists- True/False Visual Indicators */
.table-cell-boolean-true{
  background-image: url('True16.svg');
  background-repeat: no-repeat;
  background-size: 14px 14px;
  background-position-y: 25% !important;
  padding-left: 16px;
  margin-right: 6px;
}

.table-cell-boolean-false{
  background-image: url('False16.svg');
  background-repeat: no-repeat;
  background-size: 14px 14px;
  background-position-y: 25% !important;
  padding-left: 16px;
  margin-right: 6px;
}


/* 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
Have modal fit the viewport height with its own scrollbar start
*/
/* needed for the sticky table header */
.table-fixed-header {
  align-items: flex-start;
  overflow: auto;
}

.table-fixed-header thead th {
  position: sticky;
  top: 0;
  z-index: 1;
}

.table-fixed-header th {
  background:#eee; 
}
/* Have modal fit the viewport height with its own scrollbar end */

//------------------------------------------------------------------------------------------------------------------------
// STATES
//------------------------------------------------------------------------------------------------------------------------
.Waiting {
    background-color: $state-waiting-bg;
		color: $state-waiting-text;
}

.Unassigned {
  	background-color: $state-unassigned-bg;
  	color: $state-unassigned-text; 
}

.Assigned {
  	background-color: $state-assigned-bg;
		color: $state-assigned-text;
} 

.Accepted {
  	background-color: $state-accepted-bg;
